function processData(input) {
  try {
    // Agent yanıtını parse et
    let requestAnalysis;
    if (typeof input.content === 'string') {
      // JSON string ise parse et
      try {
        requestAnalysis = JSON.parse(input.content);
      } catch (e) {
        // JSON parse edilemezse metin olarak kullan
        requestAnalysis = {
          talepTuru: 'ürün önerisi',
          urunKategorisi: 'genel',
          fiyatAraligi: 'belirtilmemiş',
          ozelGereksinimler: []
        };
      }
    } else {
      requestAnalysis = input.content;
    }

    // Talep türünü belirle
    const requestType = requestAnalysis.talepTuru || requestAnalysis.talepTürü || 'ürün önerisi';

    return {
      requestType: requestType.toLowerCase().replace(' ', '-'),
      category: requestAnalysis.urunKategorisi || requestAnalysis.ürünKategorisi || 'genel',
      priceRange: requestAnalysis.fiyatAraligi || requestAnalysis.fiyatAralığı || 'belirtilmemiş',
      specialRequirements: requestAnalysis.ozelGereksinimler || requestAnalysis.özelGereksinimler || [],
      analysis: requestAnalysis
    };
  } catch (error) {
    return {
      requestType: 'ürün-önerisi',
      category: 'genel',
      priceRange: 'belirtilmemiş',
      specialRequirements: [],
      analysis: {
        talepTuru: 'ürün önerisi',
        urunKategorisi: 'genel',
        fiyatAraligi: 'belirtilmemiş',
        ozelGereksinimler: []
      },
      error: error.message
    };
  }
}

function processData(input) {
  // Gelen yanıtı al
  const content = input.content || 'Yanıt oluşturulamadı';
  const requestType = input.requestType || 'Talep türü belirlenemedi';

  // Yanıt türüne göre başlık oluştur
  let title = 'E-Ticaret Asistanı';
  if (requestType.includes('öneri')) {
    title = 'Ürün Önerileri';
  } else if (requestType.includes('bilgi')) {
    title = 'Ürün Bilgileri';
  } else if (requestType.includes('sipariş')) {
    title = 'Sipariş Durumu';
  } else if (requestType.includes('iade')) {
    title = 'İade İşlemleri';
  }

  // Ek bilgiler oluştur
  const additionalInfo = getAdditionalInfo(requestType);

  // Yanıtı formatla
  const formattedResponse = `
    # ${title}

    ${content}

    ## Ek Bilgiler
    ${additionalInfo.join('\n    ')}

    Başka bir sorunuz olursa bize ulaşmaktan çekinmeyin.
    E-Ticaret Müşteri Hizmetleri
  `;

  return {
    formattedResponse,
    requestType,
    title,
    timestamp: new Date().toISOString()
  };
}

// Talep türüne göre ek bilgiler oluştur
function getAdditionalInfo(requestType) {
  const commonInfo = [
    '🛒 Alışveriş yapmak için web sitemizi ziyaret edin.',
    '📱 Mobil uygulamamızı indirerek daha kolay alışveriş yapabilirsiniz.',
    '💳 Güvenli ödeme seçenekleri ve taksit imkanları sunuyoruz.'
  ];

  if (requestType.includes('öneri')) {
    return [
      ...commonInfo,
      '⭐ Ürünlerimiz hakkında müşteri değerlendirmelerini inceleyebilirsiniz.',
      '🔍 Detaylı ürün karşılaştırma özelliğimizi kullanabilirsiniz.'
    ];
  } else if (requestType.includes('bilgi')) {
    return [
      ...commonInfo,
      '📋 Ürün teknik özelliklerini web sitemizde bulabilirsiniz.',
      '📞 Ürün uzmanlarımızla görüşmek için müşteri hizmetlerini arayabilirsiniz.'
    ];
  } else if (requestType.includes('sipariş')) {
    return [
      ...commonInfo,
      '🚚 Kargo takibi için web sitemizi veya mobil uygulamamızı kullanabilirsiniz.',
      '📅 Teslimat tarihinde değişiklik için müşteri hizmetlerini arayabilirsiniz.'
    ];
  } else if (requestType.includes('iade')) {
    return [
      ...commonInfo,
      '↩️ İade formunu web sitemizden doldurabilirsiniz.',
      '📦 İade kargo kodunu müşteri hizmetlerinden alabilirsiniz.'
    ];
  }

  return commonInfo;
}
